import{c as i,Q as l,j as a,m as o}from"./chunks/framework.D9IbVcwA.js";const s=JSON.parse('{"title":"Terminal 终端","description":"","frontmatter":{},"headers":[],"relativePath":"document/kernel/gui/terminal.md","filePath":"document/kernel/gui/terminal.md","lastUpdated":1777209094000}'),t={name:"document/kernel/gui/terminal.md"};function r(c,e,d,n,p,u){return l(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="terminal-终端" tabindex="-1">Terminal 终端 <a class="header-anchor" href="#terminal-终端" aria-label="Permalink to &quot;Terminal 终端&quot;">​</a></h1><blockquote><p>里程碑: <code>031_gui_native_app</code> <code>035_multi_terminal</code></p></blockquote><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>GUI 模式下的终端模拟器窗口，通过 pipe 连接独立 shell 进程。支持多终端并发，每个终端绑定独立的 fork+execve shell 子进程。仅在 <code>CINUX_GUI</code> 模式下编译。</p><h2 id="terminal-窗口-kernel-gui-terminal-hpp-cpp" tabindex="-1">Terminal 窗口 (<code>kernel/gui/terminal.hpp/cpp</code>) <a class="header-anchor" href="#terminal-窗口-kernel-gui-terminal-hpp-cpp" aria-label="Permalink to &quot;Terminal 窗口 (`kernel/gui/terminal.hpp/cpp`)&quot;">​</a></h2><h3 id="内部结构" tabindex="-1">内部结构 <a class="header-anchor" href="#内部结构" aria-label="Permalink to &quot;内部结构&quot;">​</a></h3><ul><li>继承 <code>Window</code>，80x25 <code>screen_</code> 字符缓冲</li><li>光标管理 + fg/bg 颜色</li><li>pipe 指针: stdin_pipe / stdout_pipe</li></ul><h3 id="核心方法" tabindex="-1">核心方法 <a class="header-anchor" href="#核心方法" aria-label="Permalink to &quot;核心方法&quot;">​</a></h3><ul><li><code>on_key(KeyEvent&amp;)</code> — 按键写入 pipe (shell stdin)</li><li><code>on_paint(Canvas&amp;)</code> — 遍历 screen_ 调 canvas_-&gt;draw_text()，光标反色块</li><li><code>write(data)</code> — 处理控制字符 (换行、退格、滚动)</li><li><code>is_terminal() const override { return true; }</code> — 类型识别</li></ul><h3 id="关闭流程" tabindex="-1">关闭流程 <a class="header-anchor" href="#关闭流程" aria-label="Permalink to &quot;关闭流程&quot;">​</a></h3><ul><li>关闭按钮 → close pipe reader/writer</li><li><code>waitpid</code> 回收 shell 子进程</li><li>防止 zombie</li></ul><h2 id="多终端-035" tabindex="-1">多终端 (035) <a class="header-anchor" href="#多终端-035" aria-label="Permalink to &quot;多终端 (035)&quot;">​</a></h2><h3 id="创建流程-kernel-gui-gui-init-cpp" tabindex="-1">创建流程 (<code>kernel/gui/gui_init.cpp</code>) <a class="header-anchor" href="#创建流程-kernel-gui-gui-init-cpp" aria-label="Permalink to &quot;创建流程 (`kernel/gui/gui_init.cpp`)&quot;">​</a></h3><ol><li><code>create_shell_terminal()</code> 被调用</li><li>动态创建新 pipe 对 (<code>sys_pipe</code>)</li><li><code>fork()</code> → 子进程 <code>execve(&quot;/bin/sh&quot;)</code></li><li>父进程将 pipe fd 绑定到新 Terminal</li><li><code>add_window(terminal)</code> 加入 WM</li></ol><h3 id="tick-回调" tabindex="-1">tick 回调 <a class="header-anchor" href="#tick-回调" aria-label="Permalink to &quot;tick 回调&quot;">​</a></h3><ul><li><code>gui_tick_callback</code> 遍历所有窗口</li><li>对每个 <code>is_terminal()</code> 的窗口执行 <code>poll_output()</code> + <code>render_to_canvas()</code></li><li>不只是 focused 窗口，所有终端都会更新</li></ul><h2 id="shell-启动时序" tabindex="-1">Shell 启动时序 <a class="header-anchor" href="#shell-启动时序" aria-label="Permalink to &quot;Shell 启动时序&quot;">​</a></h2><ul><li>Shell 进程在 boot 时通过 <code>launch_first_user</code> 启动</li><li>Pipe 在 <code>init.cpp</code> 创建并绑定 fd 0/1</li><li>Terminal 窗口延迟到用户点击 Shell 图标时才创建</li><li>Shell 输出暂存 pipe buffer，Terminal 连接后通过 <code>poll_output</code> 取回</li></ul><h2 id="源码位置" tabindex="-1">源码位置 <a class="header-anchor" href="#源码位置" aria-label="Permalink to &quot;源码位置&quot;">​</a></h2><ul><li><code>kernel/gui/terminal.hpp/cpp</code> — Terminal 窗口</li><li><code>kernel/gui/gui_init.hpp/cpp</code> — GUI 初始化 &amp; tick 回调</li></ul>',20)])])}const m=i(t,[["render",r]]);export{s as __pageData,m as default};
